import React from 'react';
import { Link, NavLink } from 'react-router-dom';
import { useAuth } from '../auth/AuthContext';
import FlashBar from '../components/FlashBar';

function DonorLayout({ children }) {
  const { auth, flash, logout } = useAuth();

  return (
    <div className="donor-site-shell">
      <div className="donor-site-grid">
        <aside className="donor-sidebar panel">
          <div>
            <p className="eyebrow">CareFlow</p>
            <h1>CareFlow Donor Hub</h1>
            <p className="subtitle">Clean donor workspace for profile, availability, requests, and matches.</p>
          </div>

          <nav className="donor-sidebar-nav">
            <NavLink className={({ isActive }) => (isActive ? 'active' : '')} to="/donor/overview">Overview</NavLink>
            <NavLink className={({ isActive }) => (isActive ? 'active' : '')} to="/donor/profile">Profile</NavLink>
            <NavLink className={({ isActive }) => (isActive ? 'active' : '')} to="/donor/availability">Availability</NavLink>
            <NavLink className={({ isActive }) => (isActive ? 'active' : '')} to="/donor/requests">Nearby Requests</NavLink>
            <NavLink className={({ isActive }) => (isActive ? 'active' : '')} to="/donor/matches">Top Matches</NavLink>
          </nav>

          <div className="donor-site-actions">
            <span className="chip">{auth?.user?.username || 'donor'}</span>
            <Link className="nav-link" to="/">Public Site</Link>
            <button className="danger" onClick={logout}>Logout</button>
          </div>
        </aside>

        <main className="donor-site-main">
          <section className="panel full">
            <FlashBar flash={flash} />
          </section>
          {children}
        </main>
      </div>
    </div>
  );
}

export default DonorLayout;
